@interface NSString (Trim)
- (NSString *)trimmedString;
@end

// NSString+Trim.m
@implementation NSString (Trim)
- (NSString *)trimmedString {
    return [self stringByTrimmingCharactersInSet:
        [NSCharacterSet whitespaceAndNewlineCharacterSet]];
}
@end

